def trimmed_mean(nums):
    if not nums or len(nums) < 3:
        return None

    nums.sort()
    min_occurrences, max_occurrences = 0, len(nums)-1
    middle_index = (len(nums) - 1) // 2
    while min_occurrences < max_occurrences:
        diff = abs(nums[min_occurrences] - nums[max_occurrences])
        if diff > abs(nums[middle_index] - nums[min_occurrences]):
            min_occurrences += 1
        else:
            max_occurrences -= 1
    return sum(nums[min_occurrences+1 : max_occurrences]) / (max_occurrences - min_occurrences - 1)
